const state = { data:{}, maps:{}, selectedEventId:null, currentLead:null };
const riskColors = { low:'#66e0a3', medium:'#f7c948', high:'#ff6b6b', critical:'#d08cff' };
const $ = (id)=>document.getElementById(id);
const esc = (s='') => String(s).replace(/[&<>'"]/g, c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
const fmt = (d)=> new Date(d+'T00:00:00Z').toISOString().slice(0,10);
const addDays = (date, days)=>{ const d=new Date(date+'T00:00:00Z'); d.setUTCDate(d.getUTCDate()+days); return d.toISOString().slice(0,10); };

async function loadData(){
  const loaded = {};
  for (const name of DATA_FILES) {
    try {
      const res = await fetch(`data/${name}.json`);
      if (!res.ok) throw new Error(`Could not load data/${name}.json`);
      loaded[name] = await res.json();
    } catch (err) {
      console.warn(`Using bundled fallback for ${name}; local JSON fetch may be blocked when opening index.html directly.`, err);
      loaded[name] = BUNDLED_DATA[name];
    }
  }
  const local = localStorage.getItem('expowatch-edited-data');
  state.data = local ? {...loaded, ...JSON.parse(local)} : loaded;
  state.selectedEventId = state.data.events[0]?.id;
}

function riskBadge(level){ return `<span class="badge risk-${esc(level)}">${esc(level)} monitoring priority</span>`; }
function confidenceBadge(level){ return `<span class="badge confidence">confidence level: ${esc(level)}</span>`; }
function eventById(id){ return state.data.events.find(e=>e.id===id); }
function taxonById(id){ return state.data.taxa.find(t=>t.id===id); }
function websiteById(id){ return state.data.websites.find(w=>w.id===id); }
function evidenceById(id){ return state.data.evidence.find(e=>e.id===id); }
function airportByIata(iata){ return state.data.airports.find(a=>a.iata===iata || a.id===String(iata).toLowerCase()); }
function routesForEvent(id){ return state.data.routes.filter(r=>r.related_event_id===id); }
function evidenceForEvent(event){ return (event.evidence_ids||[]).map(evidenceById).filter(Boolean).concat(state.data.evidence.filter(e=>e.related_event_ids?.includes(event.id) && !(event.evidence_ids||[]).includes(e.id))); }
function websitesForEvent(event){ return (event.linked_website_ids||[]).map(websiteById).filter(Boolean); }
function taxaForEvent(event){ return (event.proxy_taxa_ids||[]).map(taxonById).filter(Boolean); }

function monitoringWindows(date){
  const today = new Date();
  return [
    ['pre','Pre-event online monitoring',addDays(date,-56),addDays(date,-14)],
    ['inbound','Inbound route-risk window',addDays(date,-14),date],
    ['event','Event window',date,addDays(date,2)],
    ['outbound','Outbound route-risk window',date,addDays(date,7)],
    ['post','Post-event online monitoring',addDays(date,1),addDays(date,30)]
  ].map(([key,label,start,end])=>({key,label,start,end,status: today < new Date(start+'T00:00:00Z') ? 'upcoming' : today > new Date(end+'T23:59:59Z') ? 'past' : 'active'}));
}
function timelineHtml(date){ return `<div class="timeline">${monitoringWindows(date).map(w=>`<div class="window ${w.status==='active'?'active':''}"><strong>${w.label}</strong><div class="bar"></div><div class="mini">${w.start} → ${w.end}</div><div class="mini">${w.status}</div></div>`).join('')}</div>`; }

function scoreEvent(event){
  const taxa = taxaForEvent(event), evidence = evidenceForEvent(event), websites = websitesForEvent(event), routes = routesForEvent(event);
  const species = Math.min(25, taxa.length * 5);
  const online = Math.min(20, evidence.filter(e=>['forum advert','social media post','attendee report','official event page'].includes(e.evidence_type)).length * 7);
  const courier = websites.some(w=>w.source_type==='courier/import-export service') ? 15 : 0;
  const inbound = routes.some(r=>r.route_type==='inbound') ? 15 : 0;
  const outbound = routes.some(r=>r.route_type==='outbound') ? 10 : 0;
  const seizure = evidence.some(e=>['seizure report','journalist report'].includes(e.evidence_type)) ? 10 : 0;
  const paperwork = evidence.some(e=>(e.extracted_red_flags||[]).join(' ').match(/source|paperwork|document|CITES|permit/i)) ? 5 : 0;
  const score = species + online + courier + inbound + outbound + seizure + paperwork;
  const priority = score >= 85 ? 'critical' : score >= 65 ? 'high' : score >= 40 ? 'medium' : 'low';
  return {score, priority, confidence:event.confidence, parts:{species,online,courier,inbound,outbound,seizure,paperwork}, explanation:[
    `${taxa.length} proxy taxa create a species-risk indicator (${species}/25).`,
    `${evidence.length} public-safe evidence items support online/event context (${online}/20).`,
    courier ? 'Courier/import-export source category is linked and should be verified (15/15).' : 'No courier/import-export source category is linked (0/15).',
    inbound ? 'Inbound route-risk corridors exist for T-14 to event date (15/15).' : 'No inbound route-risk corridor is recorded.',
    outbound ? 'Outbound route-risk corridors exist for event date to T+7 (10/10).' : 'No outbound route-risk corridor is recorded.',
    seizure ? 'Journalist/seizure report category evidence contributes contextual history (10/10).' : 'No seizure/report-history evidence category is recorded.',
    paperwork ? 'Source-claim or paperwork red flags require recommended verification (5/5).' : 'No paperwork/source-claim concern is currently recorded.',
    'This score is a monitoring priority indicator, not proof of criminality.'
  ]};
}

function initTabs(){
  document.querySelectorAll('#tabs button').forEach(btn=>btn.addEventListener('click',()=>showTab(btn.dataset.tab)));
  window.addEventListener('hashchange',()=>showTab(location.hash.replace('#','')||'dashboard'));
  showTab(location.hash.replace('#','')||'dashboard');
}
function showTab(tab){
  document.querySelectorAll('.tab-panel').forEach(p=>p.classList.toggle('active',p.id===tab));
  document.querySelectorAll('#tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));
  if (location.hash !== '#'+tab) history.replaceState(null,'','#'+tab);
  setTimeout(()=>Object.values(state.maps).forEach(m=>m?.invalidateSize()),80);
}

function renderSummary(){
  const today = new Date();
  const upcoming = state.data.events.filter(e=>new Date(e.known_dates[0]+'T00:00:00Z')>=today).length;
  const high = state.data.events.filter(e=>['high','critical'].includes(e.monitoring_priority)).length;
  const metrics = [['total events',state.data.events.length],['upcoming events',upcoming],['high-priority events',high],['proxy taxa',state.data.taxa.length],['linked websites',state.data.websites.length],['evidence items',state.data.evidence.length],['route-risk corridors',state.data.routes.length]];
  $('summaryCards').innerHTML = metrics.map(([label,num])=>`<div class="metric"><div class="num">${num}</div><div class="label">${label}</div></div>`).join('');
  $('priorityList').innerHTML = [...state.data.events].sort((a,b)=>scoreEvent(b).score-scoreEvent(a).score).slice(0,5).map(eventCard).join('');
}
function eventCard(e){ const s=scoreEvent(e); return `<article class="card"><div>${riskBadge(s.priority)} ${confidenceBadge(e.confidence)}</div><h4>${esc(e.name)}</h4><p class="mini">${esc(e.venue)} · ${esc(e.city)}, ${esc(e.country)} · ${esc(e.known_dates[0])}</p><p>${esc(e.risk_notes)}</p><button class="ghost-btn" onclick="openProfile('${e.id}')">Open event profile</button></article>`; }

function makeMap(id, center=[25,5], zoom=2){
  if (state.maps[id]) return state.maps[id];
  const map = L.map(id).setView(center, zoom);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',{attribution:'&copy; OpenStreetMap contributors'}).addTo(map);
  state.maps[id]=map; return map;
}
function addEventMarkers(map, events){
  events.forEach(e=>{
    const score=scoreEvent(e); const marker=L.circleMarker([e.latitude,e.longitude],{radius:10,color:riskColors[score.priority],fillColor:riskColors[score.priority],fillOpacity:.82,weight:2}).addTo(map);
    marker.bindPopup(`<strong>${esc(e.name)}</strong><br>${esc(e.known_dates[0])}<br>${esc(e.city)}, ${esc(e.country)}<br>${score.priority} priority<br>confidence level: ${esc(e.confidence)}<br><button onclick="openProfile('${e.id}')">Open profile</button>`);
  });
}
function renderMaps(){
  const dash=makeMap('dashboardMap'); addEventMarkers(dash,state.data.events);
  const expo=makeMap('expoMap'); addEventMarkers(expo,state.data.events);
  $('mapPriorityFilter').addEventListener('change',()=>{ expo.eachLayer(l=>{ if(l instanceof L.CircleMarker) expo.removeLayer(l); }); const val=$('mapPriorityFilter').value; addEventMarkers(expo, val==='all'?state.data.events:state.data.events.filter(e=>scoreEvent(e).priority===val)); });
  const routeMap=makeMap('routeMap'); addEventMarkers(routeMap,state.data.events); state.data.routes.slice(0,25).forEach(r=>{ const e=eventById(r.related_event_id); const ap=airportByIata(r.destination_airport||r.origin_airport); if(e&&ap) L.polyline([[e.latitude,e.longitude],[ap.latitude,ap.longitude]],{color:r.route_type==='inbound'?riskColors.medium:riskColors.high,weight:2,opacity:.45}).addTo(routeMap); });
}

function renderCalendar(){
  const q=($('calendarSearch').value||'').toLowerCase();
  $('calendarList').innerHTML = state.data.events.filter(e=>[e.name,e.city,e.country].join(' ').toLowerCase().includes(q)).sort((a,b)=>a.known_dates[0].localeCompare(b.known_dates[0])).map(e=>`<article class="card"><div class="section-head"><div><h3>${esc(e.known_dates[0])}: ${esc(e.name)}</h3><p>${esc(e.venue)} · ${esc(e.city)}, ${esc(e.country)}</p></div>${riskBadge(scoreEvent(e).priority)}</div>${timelineHtml(e.known_dates[0])}<button class="ghost-btn" onclick="openProfile('${e.id}')">Open profile</button></article>`).join('');
}

function openProfile(id){ state.selectedEventId=id; $('profileSelect').value=id; renderProfile(); showTab('profiles'); }
function renderProfileSelector(){ $('profileSelect').innerHTML = state.data.events.map(e=>`<option value="${e.id}">${esc(e.name)}</option>`).join(''); $('profileSelect').value=state.selectedEventId; $('profileSelect').onchange=e=>{state.selectedEventId=e.target.value; renderProfile();}; }
function renderProfile(){
  const e=eventById(state.selectedEventId)||state.data.events[0]; if(!e) return; const s=scoreEvent(e), taxa=taxaForEvent(e), websites=websitesForEvent(e), evidence=evidenceForEvent(e), routes=routesForEvent(e);
  $('profileDetail').innerHTML = `<div class="card"><div class="section-head"><div><h2>${esc(e.name)}</h2><p>${esc(e.type)} · ${esc(e.venue)} · ${esc(e.city)}, ${esc(e.country)}</p></div><div>${riskBadge(s.priority)} ${confidenceBadge(e.confidence)}</div></div><p>${esc(e.risk_notes)}</p>${timelineHtml(e.known_dates[0])}</div><div class="profile-grid"><section class="card"><h3>Why flagged?</h3><div class="metric"><div class="num">${s.score}</div><div class="label">monitoring priority score</div></div><ul>${s.explanation.map(x=>`<li>${esc(x)}</li>`).join('')}</ul></section><section class="card"><h3>Possible origin and consumer countries</h3><p><strong>Possible origin country:</strong> ${e.possible_origin_countries.map(esc).join(', ')}</p><p><strong>Possible consumer countries:</strong> ${e.possible_consumer_countries.map(esc).join(', ')}</p><p><strong>Nearest airports:</strong> ${e.nearest_airports.map(esc).join(', ')}</p></section></div>${sectionCards('Linked websites',websites.map(w=>`<strong>${esc(w.name)}</strong><p class="mini">${esc(w.source_type)} · ${esc(w.confidence)} · checked ${esc(w.last_checked)}</p><p>${esc(w.notes)}</p><a href="${esc(w.url)}" target="_blank" rel="noopener">Open source</a>`))}${sectionCards('High-risk proxy taxa',taxa.map(t=>`<strong><em>${esc(t.scientific_name)}</em></strong><p>${esc(t.common_name)} · ${esc(t.taxon_group)} · CITES ${esc(t.cites_appendix)} · EU ${esc(t.eu_annex)}</p><p>${esc(t.officer_identification_notes)}</p>`))}${sectionCards('Route-risk corridors',routes.map(routeHtml))}${sectionCards('Evidence items',evidence.map(evidenceHtml))}<div class="profile-grid"><section class="card"><h3>Recommended investigation questions</h3><ul><li>Which source claims and permit-chain records require recommended verification?</li><li>Which public evidence items should be preserved with URL and date observed?</li><li>Which partner agency can verify taxon ID and document consistency?</li></ul></section><section class="card"><h3>Disruption impacts</h3><ul>${disruptionImpacts().map(x=>`<li>${x}</li>`).join('')}</ul></section></div>`;
}
function sectionCards(title, cards){ return `<section><h3>${title}</h3><div class="card-grid">${cards.map(c=>`<article class="card">${c}</article>`).join('')}</div></section>`; }
function routeHtml(r){ return `<div class="route-card"><strong>${esc(r.route_type)}: ${esc(r.origin_country_or_region)} → ${esc(r.destination_country_or_region)}</strong><p class="mini">Window: ${esc(r.timing_window)} · confidence level: ${esc(r.confidence)}</p><p>${esc(r.rationale)}</p><p class="mini">${esc(r.data_basis)}</p><p><strong>${esc(r.caveat)}</strong></p></div>`; }
function evidenceHtml(e){ return `<strong>${esc(e.title)}</strong><p class="evidence-kind">${esc(e.evidence_type)} · confidence level: ${esc(e.confidence)}</p><p>${esc(e.summary)}</p><p class="mini">Red flags: ${(e.extracted_red_flags||[]).map(esc).join('; ')}</p>`; }
function disruptionImpacts(){ return ['Pre-event monitoring may identify sellers before movement.','Event inspection may interrupt handover.','Courier/export checks may disrupt onward movement.','Permit-chain verification may expose false source claims.','Post-event monitoring may identify destination-country buyer networks.']; }

function renderTaxa(){
  const groups=[...new Set(state.data.taxa.map(t=>t.taxon_group))]; $('taxaGroupFilter').innerHTML='<option value="all">All groups</option>'+groups.map(g=>`<option>${esc(g)}</option>`).join('');
  const cites=[...new Set(state.data.taxa.map(t=>t.cites_appendix))]; $('taxaCitesFilter').innerHTML='<option value="all">All CITES</option>'+cites.map(g=>`<option>${esc(g)}</option>`).join('');
  const update=()=>{ const q=$('taxaSearch').value.toLowerCase(), group=$('taxaGroupFilter').value, cites=$('taxaCitesFilter').value, origin=$('taxaOriginFilter').value.toLowerCase(), conf=$('taxaConfidenceFilter').value, basis=$('taxaBasisFilter').value.toLowerCase(); $('taxaCards').innerHTML=state.data.taxa.filter(t=>(!q||[t.scientific_name,t.common_name].join(' ').toLowerCase().includes(q))&&(group==='all'||t.taxon_group===group)&&(cites==='all'||t.cites_appendix===cites)&&(!origin||t.possible_origin_countries.join(' ').toLowerCase().includes(origin))&&(conf==='all'||t.confidence===conf)&&(!basis||t.evidence_basis.toLowerCase().includes(basis))).map(t=>`<article class="card"><h3><em>${esc(t.scientific_name)}</em></h3><p>${esc(t.common_name)} · ${esc(t.taxon_group)}</p><p>CITES ${esc(t.cites_appendix)} · EU ${esc(t.eu_annex)} · ${confidenceBadge(t.confidence)}</p><p><strong>Possible origin country:</strong> ${t.possible_origin_countries.map(esc).join(', ')}</p><p>${esc(t.reason_for_inclusion)}</p><p class="mini">${esc(t.officer_identification_notes)}</p><button class="ghost-btn" onclick="checkGbif('${t.id}')">Check GBIF taxonomy/range</button><div id="gbif-${t.id}" class="notice"></div></article>`).join(''); };
  ['taxaSearch','taxaGroupFilter','taxaCitesFilter','taxaOriginFilter','taxaConfidenceFilter','taxaBasisFilter'].forEach(id=>$(id).oninput=update); update();
}
async function checkGbif(id){ const t=taxonById(id), el=$(`gbif-${id}`); el.textContent='Checking GBIF public API...'; try{ const match=await fetch(`https://api.gbif.org/v1/species/match?name=${encodeURIComponent(t.scientific_name)}`).then(r=>r.json()); const occ=match.usageKey?await fetch(`https://api.gbif.org/v1/occurrence/search?taxon_key=${match.usageKey}&limit=3`).then(r=>r.json()):null; el.innerHTML=`<strong>GBIF biological context only:</strong> ${esc(match.scientificName||match.canonicalName||'No match')} (${esc(match.status||'unknown status')}). Occurrence sample count returned: ${occ?.results?.length ?? 0}. Not legal origin proof.`; }catch(err){ el.innerHTML='GBIF lookup failed or was blocked. Use GBIF.org manually for biological context; do not treat range data as legal origin proof.'; } }

function renderWebsites(){ const update=()=>{ const q=($('websiteSearch').value||'').toLowerCase(); $('websiteCards').innerHTML=state.data.websites.filter(w=>JSON.stringify(w).toLowerCase().includes(q)).map(w=>`<article class="card"><h3>${esc(w.name)}</h3><p>${esc(w.source_type)} · ${confidenceBadge(w.confidence)}</p><p>Related events: ${w.related_event_ids.map(id=>esc(eventById(id)?.name||id)).join(', ')}</p><p>${esc(w.notes)}</p><p class="mini">Last checked: ${esc(w.last_checked)}</p><a href="${esc(w.url)}" target="_blank" rel="noopener">Open URL</a></article>`).join(''); }; $('websiteSearch').oninput=update; update(); }
function renderRoutes(){ $('routeCards').innerHTML=state.data.routes.map(r=>`<article class="card">${routeHtml(r)}<p><strong>Event:</strong> ${esc(eventById(r.related_event_id)?.name||r.related_event_id)}</p><p><strong>Relevant proxy taxa:</strong> ${r.relevant_taxa_ids.map(id=>esc(taxonById(id)?.scientific_name||id)).join(', ')}</p></article>`).join(''); }
async function refreshAirports(){ const status=$('airportRefreshStatus'); status.textContent='Trying OurAirports public CSV...'; try{ const url='https://davidmegginson.github.io/ourairports-data/airports.csv'; const csv=await fetch(url).then(r=>{if(!r.ok) throw new Error(r.status); return r.text();}); const parsed=Papa.parse(csv,{header:true,skipEmptyLines:true}); const airports=parsed.data.filter(r=>r.iata_code&&['large_airport','medium_airport'].includes(r.type)).slice(0,5000).map(r=>({id:r.iata_code.toLowerCase(),name:r.name,iata:r.iata_code,icao:r.ident,city:r.municipality,country:r.iso_country,latitude:Number(r.latitude_deg),longitude:Number(r.longitude_deg),airport_type:r.type})); localStorage.setItem('expowatch-airports-refresh',JSON.stringify(airports)); state.data.airports=airports; status.textContent=`Loaded ${airports.length} public airport records into browser localStorage. Bundled data remains the fallback.`; }catch(err){ status.textContent='OurAirports refresh failed or was blocked. Continuing with bundled local airport data.'; } }

function renderEvidence(){ $('gdeltEvent').innerHTML='<option value="">Event context</option>'+state.data.events.map(e=>`<option value="${e.id}">${esc(e.name)}</option>`).join(''); $('gdeltSpecies').innerHTML='<option value="">Species context</option>'+state.data.taxa.map(t=>`<option value="${t.id}">${esc(t.scientific_name)}</option>`).join(''); $('evidenceCards').innerHTML=state.data.evidence.map(e=>`<article class="card">${evidenceHtml(e)}<a href="${esc(e.url)}" target="_blank" rel="noopener">Open URL</a></article>`).join(''); }
async function searchGdelt(){ const kw=$('gdeltKeyword').value||'reptile smuggling'; const ev=eventById($('gdeltEvent').value); const tx=taxonById($('gdeltSpecies').value); const queries=[kw,'wildlife seizure reptile','reptile expo']; if(tx) queries.push(`${tx.scientific_name} smuggling`); if(ev) queries.push(`${ev.name} reptile`,`${ev.name} CITES`,`${ev.city} reptile seizure`); const query='('+queries.map(q=>`"${q}"`).join(' OR ')+')'; const params=new URLSearchParams({query,mode:'artlist',format:'json',maxrecords:'20'}); if($('gdeltStart').value) params.set('startdatetime',$('gdeltStart').value.replaceAll('-','')+'000000'); if($('gdeltEnd').value) params.set('enddatetime',$('gdeltEnd').value.replaceAll('-','')+'235959'); const url='https://api.gdeltproject.org/api/v2/doc/doc?'+params; $('gdeltStatus').innerHTML=`Searching public GDELT DOC API. <a href="${url}" target="_blank">Open query manually</a>`; try{ const data=await fetch(url).then(r=>{if(!r.ok) throw new Error(r.status); return r.json();}); const articles=data.articles||[]; $('gdeltResults').innerHTML=articles.map((a,i)=>`<article class="card"><h3>${esc(a.title)}</h3><p class="mini">${esc(a.sourceCountry||a.domain||'public web')} · ${esc(a.seendate||'')}</p><p>${esc(a.snippet||'No snippet returned.')}</p><p class="mini">Matched query: ${esc(query)}</p><a href="${esc(a.url)}" target="_blank" rel="noopener">Open result</a><button class="ghost-btn" onclick="draftEvidenceFromGdelt(${i})">Copy result into draft evidence item</button></article>`).join('')||'<p>No public news results returned.</p>'; state.gdeltArticles=articles; }catch(err){ $('gdeltStatus').innerHTML=`GDELT failed due to network/CORS/API availability. Open manually: <a href="${url}" target="_blank">GDELT query URL</a>`; } }
function draftEvidenceFromGdelt(i){ const a=state.gdeltArticles?.[i]; if(!a) return; $('editEvidenceTitle').value=a.title||'Public news result'; $('editEvidenceSummary').value=`Public news result from ${a.domain||'GDELT'}: ${a.snippet||''} URL: ${a.url||''}`; showTab('editor'); }

function renderLead(){ const id=$('leadEventSelect').value||state.selectedEventId; const e=eventById(id); if(!e) return; const s=scoreEvent(e), taxa=taxaForEvent(e), websites=websitesForEvent(e), evidence=evidenceForEvent(e), routes=routesForEvent(e); const html=`<h3>${esc(e.name)} lead package</h3><p><strong>Caveat:</strong> This lead package is an intelligence support product, not proof of criminality.</p><p><strong>Date:</strong> ${esc(e.known_dates[0])}. <strong>Venue:</strong> ${esc(e.venue)}, ${esc(e.city)}, ${esc(e.country)}. <strong>Confidence level:</strong> ${esc(e.confidence)}.</p><h4>Monitoring windows</h4>${timelineHtml(e.known_dates[0])}<h4>Why flagged</h4><p>Score: ${s.score}; priority category: ${s.priority}.</p><ul>${s.explanation.map(x=>`<li>${esc(x)}</li>`).join('')}</ul><h4>High-risk proxy taxa</h4><p>${taxa.map(t=>esc(t.scientific_name)).join(', ')}</p><h4>Possible origin/source countries</h4><p>${e.possible_origin_countries.map(esc).join(', ')}</p><h4>Possible consumer countries</h4><p>${e.possible_consumer_countries.map(esc).join(', ')}</p><h4>Linked websites</h4><ul>${websites.map(w=>`<li>${esc(w.name)} — ${esc(w.source_type)}</li>`).join('')}</ul><h4>Route-risk corridors</h4><ul>${routes.map(r=>`<li>${esc(r.route_type)}: ${esc(r.origin_country_or_region)} to ${esc(r.destination_country_or_region)} (${esc(r.timing_window)}). ${esc(r.caveat)}</li>`).join('')}</ul><h4>Evidence basis</h4><ul>${evidence.map(ev=>`<li>${esc(ev.title)} — ${esc(ev.evidence_type)} — ${esc(ev.confidence)}</li>`).join('')}</ul><h4>Recommended verification questions and intervention points</h4><ul><li>Verify source claims, permits, and taxon identity.</li><li>Preserve public evidence with URL and date observed.</li><li>Coordinate only public-safe route-risk corridor review with authorized partners.</li></ul><h4>Disruption impacts</h4><ul>${disruptionImpacts().map(x=>`<li>${x}</li>`).join('')}</ul>`; $('leadPackage').innerHTML=html; state.currentLead={event_id:e.id, generated_at:new Date().toISOString(), score:s, html}; }
function exportDownload(filename, text, type='application/json'){ const a=document.createElement('a'); a.href=URL.createObjectURL(new Blob([text],{type})); a.download=filename; a.click(); URL.revokeObjectURL(a.href); }

function renderEditor(){ $('editEvidenceEvent').innerHTML=state.data.events.map(e=>`<option value="${e.id}">${esc(e.name)}</option>`).join(''); $('dataPreview').textContent=JSON.stringify(state.data,null,2).slice(0,50000); }
function addEvidence(){ const eventId=$('editEvidenceEvent').value; const item={id:'local-evidence-'+Date.now(),title:$('editEvidenceTitle').value||'Local draft evidence item',evidence_type:'open web search result',url:'',date_observed:new Date().toISOString().slice(0,10),date_posted:'',related_event_ids:[eventId],related_taxa_ids:eventById(eventId)?.proxy_taxa_ids?.slice(0,2)||[],summary:$('editEvidenceSummary').value||'Browser-memory analyst draft evidence summary.',extracted_red_flags:['requires recommended verification'],analyst_notes:'Local browser draft; export JSON to preserve.',confidence:$('editEvidenceConfidence').value,public_safe:true}; state.data.evidence.push(item); eventById(eventId)?.evidence_ids?.push(item.id); renderAll(); showTab('editor'); }

function renderAll(){ renderSummary(); renderCalendar(); renderProfileSelector(); renderProfile(); renderTaxa(); renderWebsites(); renderRoutes(); renderEvidence(); $('leadEventSelect').innerHTML=state.data.events.map(e=>`<option value="${e.id}">${esc(e.name)}</option>`).join(''); renderLead(); renderEditor(); }
function bindUi(){ $('calendarSearch').oninput=renderCalendar; $('refreshAirportsBtn').onclick=refreshAirports; $('gdeltSearchBtn').onclick=searchGdelt; $('generateLeadBtn').onclick=renderLead; $('leadEventSelect').onchange=renderLead; $('printLeadBtn').onclick=()=>print(); $('copyLeadBtn').onclick=()=>navigator.clipboard?.writeText($('leadPackage').innerText); $('exportLeadBtn').onclick=()=>exportDownload('expowatch-lead-package.json',JSON.stringify(state.currentLead,null,2)); $('addEvidenceBtn').onclick=addEvidence; $('saveLocalBtn').onclick=()=>{localStorage.setItem('expowatch-edited-data',JSON.stringify(state.data)); alert('Saved to localStorage.');}; $('exportDataBtn').onclick=()=>exportDownload('expowatch-edited-data.json',JSON.stringify(state.data,null,2)); $('importDataBtn').onclick=()=>{try{state.data=JSON.parse($('importDataText').value); renderAll(); alert('Imported into browser memory.');}catch(e){alert('Invalid JSON.');}}; $('resetDataBtn').onclick=$('resetLocalBtn').onclick=()=>{localStorage.removeItem('expowatch-edited-data'); location.reload();}; $('printPageBtn').onclick=()=>print(); }

window.openProfile=openProfile; window.checkGbif=checkGbif; window.draftEvidenceFromGdelt=draftEvidenceFromGdelt;
loadData().then(()=>{ initTabs(); bindUi(); renderAll(); renderMaps(); }).catch(err=>{ document.body.innerHTML = `<main class="card"><h1>ExpoWatch data load error</h1><p>${esc(err.message)}</p><p>If opened from the file system and your browser blocks local JSON fetches, use GitHub Pages or a simple local static server. No backend is required.</p></main>`; });
